import{_ as i,o as e,c as s,ag as l}from"./chunks/framework.Cqf6AMW8.js";const u=JSON.parse('{"title":"CSV 数据格式","description":"CSV 数据格式的基础知识点，包括语法规则、数据类型、注释等。","frontmatter":{"title":"CSV 数据格式","description":"CSV 数据格式的基础知识点，包括语法规则、数据类型、注释等。","date":"2026-04-21T00:00:00.000Z","tags":["CSV","数据序列化"],"sidebar":"auto"},"headers":[],"relativePath":"docs/data/ds-2-CSV.md","filePath":"docs/data/ds-2-CSV.md","lastUpdated":1776715536000}'),t={name:"docs/data/ds-2-CSV.md"};function h(n,a,r,d,o,c){return e(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="数据序列化" tabindex="-1">数据序列化 <a class="header-anchor" href="#数据序列化" aria-label="Permalink to &quot;数据序列化&quot;">​</a></h1><p>======================================================</p><h2 id="csv-基础知识点" tabindex="-1">CSV 基础知识点 <a class="header-anchor" href="#csv-基础知识点" aria-label="Permalink to &quot;CSV 基础知识点&quot;">​</a></h2><p>======================================================</p><h3 id="_1-基本结构" tabindex="-1">1. 基本结构 <a class="header-anchor" href="#_1-基本结构" aria-label="Permalink to &quot;1. 基本结构&quot;">​</a></h3><ul><li>CSV（Comma-Separated Values）是一种纯文本格式，使用逗号分隔值，通常用于存储表格数据。</li></ul><h3 id="_2-语法规则" tabindex="-1">2. 语法规则 <a class="header-anchor" href="#_2-语法规则" aria-label="Permalink to &quot;2. 语法规则&quot;">​</a></h3><ul><li>每行表示一条记录，字段间用逗号分隔。</li><li>包含逗号、引号或换行符的字段需要用双引号包裹。</li></ul><h3 id="_3-数据类型" tabindex="-1">3. 数据类型 <a class="header-anchor" href="#_3-数据类型" aria-label="Permalink to &quot;3. 数据类型&quot;">​</a></h3><ul><li>所有值默认视为字符串，解析时由应用程序根据需要转换类型。</li></ul><h3 id="_4-注释" tabindex="-1">4. 注释 <a class="header-anchor" href="#_4-注释" aria-label="Permalink to &quot;4. 注释&quot;">​</a></h3><ul><li>标准 CSV 不支持注释，如需注释通常在文件开头添加特殊行（如以 # 开头）。</li></ul><h3 id="_5-表头" tabindex="-1">5. 表头 <a class="header-anchor" href="#_5-表头" aria-label="Permalink to &quot;5. 表头&quot;">​</a></h3><ul><li>第一行通常作为表头，定义各列的名称。</li></ul><h3 id="_6-分隔符" tabindex="-1">6. 分隔符 <a class="header-anchor" href="#_6-分隔符" aria-label="Permalink to &quot;6. 分隔符&quot;">​</a></h3><ul><li>标准分隔符是逗号（,），但也支持其他分隔符（如分号 ;、制表符 \\t）。</li></ul><h3 id="_7-空值" tabindex="-1">7. 空值 <a class="header-anchor" href="#_7-空值" aria-label="Permalink to &quot;7. 空值&quot;">​</a></h3><ul><li>连续的逗号表示空值，如 <code>value,,value</code> 表示中间字段为空。</li></ul><h3 id="_8-示例" tabindex="-1">8. 示例 <a class="header-anchor" href="#_8-示例" aria-label="Permalink to &quot;8. 示例&quot;">​</a></h3><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">age,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">city</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">John,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">30,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">New York</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jane,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">25,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Los Angeles</span></span></code></pre></div><p>======================================================</p>`,21)])])}const k=i(t,[["render",h]]);export{u as __pageData,k as default};
